client.commands = new Collection();

const commands = client.commands;

client.on("interaction", async (interaction) => {

  if (!interaction.isCommand()) return;

  const command = interaction.commandName;

  if (!client.commands.has(command)) return interaction.reply({ content: "Invalid command", ephemeral: true });

  const args = interaction.options;
  const commandArgs = args.array();

  try {
    let runCommand = client.commands.get(command);

    if (!runCommand) return runCommand = client.commands.find((cmd) => cmd.name === command);

    client.commands.delete(command);

    runCommand = require(`../commands/${command}.js`);

