    let commandUsage = runCommand.usage;

    if (!commandUsage) commandUsage = `${commandName} <args>`;

    let commandArgsString = "";

    if (commandArgs.length > 0) {

      for (let x = 0; x < commandArgs.length; x++) {

        let cmdArg = commandArgs[x];

        if (cmdArg.required == true) cmdArg.required = false;

        if (cmdArg.required == false && cmdArg.value == undefined) {

          cmdArg.value = null;

        }

      }

    }

    let argsString = "";

    if (commandArgs.length > 0) {

      argsString = `<${commandArgs.map((arg) => arg.name).join(", ")}>:`;

    }

    let commandDocument = {

      name: commandName,

      description: commandDescription,

      usage: argsString + ` ${commandUsage}`,

