        icon_url: null

      },

      timestamp: true

    };

    interaction.reply({

      content: `Ban | ${commandName}`,

      embeds: [commandEmbed]

    });

  } catch (error) {

    console.log(error);

    interaction.reply({

      content: "An error occurred, please try again later. ",
